import OpenAI from 'openai'; const client=new OpenAI({apiKey:process.env.OPENAI_API_KEY}); export async function generateCommentary(payload){const {metrics,riskMetrics,benchmarkData,peerData,fundObjective}=payload; const prompt=`You are a senior investment reporting analyst. Write concise professional bullet points under: 1. Fund Summary 2. Performance vs Benchmark 3. Peer Comparison 4. Market Outlook\nFund Objective: ${fundObjective}\nMetrics: ${JSON.stringify(metrics)}\nRisk: ${JSON.stringify(riskMetrics)}\nBenchmark: ${JSON.stringify(benchmarkData)}\nPeers: ${JSON.stringify(peerData)}`; try{const res=await client.chat.completions.create({model:'gpt-4o-mini',messages:[{role:'system',content:'You are a professional investment reporting analyst.'},{role:'user',content:prompt}],temperature:0.6}); return res.choices[0].message.content;}catch{return `• Fund delivered an average return of ${metrics.avg_return.toFixed(2)}%.\n• Alpha versus benchmark stood at ${benchmarkData.alpha.toFixed(2)}%.\n• Relative to peers, the fund delivered ${peerData.relative_vs_peers.toFixed(2)}% excess return.\n• Volatility measured ${riskMetrics.volatility.toFixed(2)}% with Sharpe ratio of ${riskMetrics.sharpe_ratio.toFixed(2)}.`;}}